queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPrograms ?child ; p:hasDistricts ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Districts } }
  FILTER(?nf = ?total)
}

