ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPrograms ?child ; p:hasDistricts ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Districts } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?name2 WHERE {
  ?districts_programs a :Districts_Programs .
  ?programs a :Programs .
  ?districts_programs p:hasPrograms ?programs .
  ?districts a :Districts .
  ?districts_programs p:hasDistricts ?districts .
  ?districts p:name ?name .
  ?programs p:name ?name2 .
} }
}

